/* ── Card ── */
function ProjectCard({
	project,
	theme,
}: {
	project: (typeof projects)[0]
	theme: string
}) {
	const isDark = theme === 'dark'
	const ref = useRef<HTMLDivElement>(null)
	const [hovered, setHovered] = useState(false)

	/* 3-D tilt */
	const mx = useMotionValue(0)
	const my = useMotionValue(0)
	const rotateX = useSpring(useTransform(my, [-0.5, 0.5], [5, -5]), { stiffness: 280, damping: 28 })
	const rotateY = useSpring(useTransform(mx, [-0.5, 0.5], [-5, 5]), { stiffness: 280, damping: 28 })

	function onMove(e: React.MouseEvent<HTMLDivElement>) {
		if (!ref.current) return
		const r = ref.current.getBoundingClientRect()
		mx.set((e.clientX - r.left) / r.width - 0.5)
		my.set((e.clientY - r.top) / r.height - 0.5)
	}
	function onLeave() {
		mx.set(0)
		my.set(0)
		setHovered(false)
	}

	const bgFrom = isDark ? project.gradientFromDark : project.gradientFrom
	const bgTo   = isDark ? project.gradientToDark   : project.gradientTo

	return (
		<motion.div
			ref={ref}
			onMouseMove={onMove}
			onMouseEnter={() => setHovered(true)}
			onMouseLeave={onLeave}
			style={{ rotateX, rotateY, transformStyle: 'preserve-3d', perspective: 900 }}
			variants={{
				hidden:   { opacity: 0, y: 44 },
				visible:  { opacity: 1, y: 0, transition: { duration: 0.68, ease: [0.22, 1, 0.36, 1] } },
			}}
		>
			<motion.article
				className='flex flex-col rounded-3xl overflow-hidden'
				animate={{ y: hovered ? -10 : 0 }}
				transition={{ duration: 0.36, ease: [0.22, 1, 0.36, 1] }}
				style={{
					background: isDark ? 'rgba(255,255,255,0.035)' : '#ffffff',
					border: hovered
						? `1.5px solid ${project.color}55`
						: isDark
						? '1.5px solid rgba(255,255,255,0.09)'
						: '1.5px solid rgba(0,0,0,0.09)',
					boxShadow: hovered
						? isDark
							? `0 30px 64px -16px ${project.color}38, 0 0 0 1px ${project.color}22`
							: `0 30px 64px -16px ${project.color}30, 0 4px 16px rgba(0,0,0,0.07)`
						: isDark
						? '0 2px 24px rgba(0,0,0,0.45)'
						: '0 2px 18px rgba(0,0,0,0.07)',
					transition: 'border 0.28s ease, box-shadow 0.36s ease',
				}}
			>
				{/* ── Preview ── */}
				<div
					className='relative overflow-hidden flex-shrink-0'
					style={{
						height: '15rem',
						background: `linear-gradient(140deg, ${bgFrom} 0%, ${bgTo} 100%)`,
					}}
				>
					{/* dot grid */}
					<div
						className='absolute inset-0'
						style={{
							backgroundImage: `radial-gradient(circle at 1.5px 1.5px, ${project.color} 1.5px, transparent 0)`,
							backgroundSize: '26px 26px',
							opacity: isDark ? 0.15 : 0.18,
						}}
					/>

					{/* ambient glow */}
					<div
						className='absolute rounded-full blur-3xl pointer-events-none'
						style={{
							width: 260, height: 260,
							top: '50%', left: '50%',
							transform: 'translate(-50%,-50%)',
							background: `radial-gradient(circle, ${project.color}28 0%, transparent 70%)`,
						}}
					/>

					{/* icon — zooms on hover */}
					<motion.div
						className='absolute inset-0 flex items-center justify-center'
						animate={hovered ? { scale: 1.1 } : { scale: 1 }}
						transition={{ duration: 0.5, ease: 'easeOut' }}
					>
						<div
							className='rounded-2xl p-5'
							style={{
								background: isDark ? `${project.color}22` : `${project.color}18`,
								border: `1.5px solid ${project.color}30`,
								boxShadow: `0 10px 28px -6px ${project.color}30`,
							}}
						>
							<svg
								width='44' height='44' viewBox='0 0 24 24' fill='none'
								stroke={project.color} strokeWidth='1.5'
								strokeLinecap='round' strokeLinejoin='round'
							>
								<path d={project.iconPath} />
							</svg>
						</div>
					</motion.div>

					{/* label badge */}
					<div
						className='absolute top-4 left-4 px-3 py-1.5 rounded-full text-xs font-semibold tracking-wide'
						style={{
							background: isDark ? `${project.color}28` : `${project.color}16`,
							color: isDark ? project.colorLight : project.color,
							border: `1px solid ${project.color}35`,
						}}
					>
						{project.label}
					</div>

					{/* hover overlay */}
					<motion.div
						className='absolute inset-0 flex items-center justify-center'
						style={{
							background: `linear-gradient(155deg, ${project.color}e0 0%, rgba(0,0,0,0.76) 100%)`,
						}}
						animate={{ opacity: hovered ? 1 : 0 }}
						transition={{ duration: 0.26 }}
					>
						<motion.div
							className='flex items-center gap-2 text-white font-semibold text-sm tracking-wide'
							animate={hovered ? { y: 0, opacity: 1 } : { y: 10, opacity: 0 }}
							transition={{ duration: 0.26, delay: 0.05 }}
						>
							<ArrowUpRight size={16} />
							View Project
						</motion.div>
					</motion.div>
				</div>

				{/* ── Body ── */}
				<div className='flex flex-col flex-1 p-8 gap-5'>
					{/* title */}
					<h3
						className='text-2xl font-bold leading-snug tracking-tight'
						style={{ color: 'var(--text)' }}
					>
						{project.title}
					</h3>

					{/* description */}
					<p
						className='text-base leading-relaxed flex-1'
						style={{ color: 'var(--text-secondary)', lineHeight: '1.7' }}
					>
						{project.description}
					</p>

					{/* tech tags */}
					<div className='flex flex-wrap gap-2'>
						{project.tech.map(t => (
							<span
								key={t}
								className='px-4 py-1.5 rounded-full text-sm font-semibold'
								style={{
									background: isDark ? `${project.color}18` : `${project.color}10`,
									color: isDark ? project.colorLight : project.color,
									border: `1px solid ${project.color}2e`,
								}}
							>
								{t}
							</span>
						))}
					</div>

					{/* divider */}
					<div
						className='h-px w-full'
						style={{ background: isDark ? 'rgba(255,255,255,0.07)' : 'rgba(0,0,0,0.07)' }}
					/>

					{/* buttons */}
					<div className='flex gap-4'>
						<motion.a
							href={project.demo}
							className='flex-1 flex items-center justify-center gap-2 px-6 py-3 rounded-xl text-base font-semibold text-white'
							style={{
								background: `linear-gradient(135deg, ${project.color} 0%, ${project.colorLight} 100%)`,
								boxShadow: hovered ? `0 8px 24px -4px ${project.color}60` : 'none',
								transition: 'box-shadow 0.3s ease',
							}}
							whileHover={{ scale: 1.04, y: -2 }}
							whileTap={{ scale: 0.97 }}
						>
							<ExternalLink size={16} />
							Live Demo
						</motion.a>

						<motion.a
							href={project.github}
							className='flex-1 flex items-center justify-center gap-2 px-6 py-3 rounded-xl text-base font-semibold'
							style={{
								background: isDark ? 'rgba(255,255,255,0.06)' : '#f8fafc',
								color: isDark ? '#cbd5e1' : '#475569',
								border: isDark
									? '1.5px solid rgba(255,255,255,0.11)'
									: '1.5px solid #e2e8f0',
								transition: 'background 0.2s ease, border-color 0.2s ease',
							}}
							whileHover={{ scale: 1.04, y: -2 }}
							whileTap={{ scale: 0.97 }}
						>
							<Github size={16} />
							View Code
						</motion.a>
					</div>
				</div>
			</motion.article>
		</motion.div>
	)
}

